package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;

import java.io.File;
import java.nio.file.Files;
import java.nio.file.Paths;

public class Main {

    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java Main <file-to-fix>");
            System.exit(1);
        }

        String filePath = args[0];
        File file = new File(filePath);

        if (!file.exists()) {
            System.err.println("File not found: " + filePath);
            System.exit(1);
        }

        CompilationUnit cu = StaticJavaParser.parse(file);

        new GetLoggerManagerRemover().visit(cu, null);

        Files.write(Paths.get(filePath), cu.toString().getBytes());

        System.out.println("Transformation applied successfully to: " + filePath);
    }

    static class GetLoggerManagerRemover extends VoidVisitorAdapter<Void> {
        @Override
        public void visit(MethodCallExpr n, Void arg) {
            super.visit(n, arg);

            if ("getLoggerManager".equals(n.getNameAsString())) {
                n.getParentNode().ifPresent(parent -> {
                    if (parent instanceof ExpressionStmt) {
                        parent.remove();
                    } else if (parent instanceof MethodCallExpr) {
                        MethodCallExpr parentCall = (MethodCallExpr) parent;
                        parentCall.getScope().ifPresent(scope -> {
                            if (scope instanceof MethodCallExpr) {
                                MethodCallExpr scopeCall = (MethodCallExpr) scope;
                                scopeCall.getScope().ifPresent(grandparentScope -> {
                                    if (grandparentScope instanceof MethodCallExpr) {
                                        MethodCallExpr grandparentCall = (MethodCallExpr) grandparentScope;
                                        grandparentCall.getScope().ifPresent(ggScope -> {
                                            if (ggScope instanceof MethodCallExpr) {
                                                MethodCallExpr ggCall = (MethodCallExpr) ggScope;
                                                ggCall.replace(n);
                                            }
                                        });
                                    } else {
                                        grandparentCall.replace(n);
                                    }
                                });
                            }
                        });
                    }
                });
            }
        }

        @Override
        public void visit(MethodDeclaration n, Void arg) {
            super.visit(n, arg);
        }
    }
}

package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.expr.Expression;
import com.github.javaparser.ast.expr.MethodCallExpr;
import com.github.javaparser.ast.stmt.ExpressionStmt;
import com.github.javaparser.ast.visitor.VoidVisitorAdapter;

import java.io.File;
import java.nio.file.Files;
import java.nio.file.Paths;
import java.util.ArrayList;
import java.util.List;

public class Main {

    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java Main <file-to-fix>");
            System.exit(1);
        }

        String filePath = args[0];
        File file = new File(filePath);

        if (!file.exists()) {
            System.err.println("File not found: " + filePath);
            System.exit(1);
        }

        CompilationUnit cu = StaticJavaParser.parse(file);

        GetLoggerManagerRemover remover = new GetLoggerManagerRemover();
        remover.visit(cu, null);

        List<ExpressionStmt> toRemove = remover.getStatementsToRemove();
        for (ExpressionStmt stmt : toRemove) {
            stmt.remove();
        }

        Files.write(Paths.get(filePath), cu.toString().getBytes());

        System.out.println("Transformation applied successfully to: " + filePath);
    }

    static class GetLoggerManagerRemover extends VoidVisitorAdapter<Void> {
        private final List<ExpressionStmt> statementsToRemove = new ArrayList<>();

        public List<ExpressionStmt> getStatementsToRemove() {
            return statementsToRemove;
        }

        @Override
        public void visit(MethodCallExpr n, Void arg) {
            super.visit(n, arg);

            if ("getLoggerManager".equals(n.getNameAsString())) {
                Expression parent = n.getParentNode().orElse(null);
                if (parent instanceof ExpressionStmt) {
                    statementsToRemove.add((ExpressionStmt) parent);
                } else if (parent instanceof MethodCallExpr) {
                    MethodCallExpr parentCall = (MethodCallExpr) parent;
                    Expression grandparent = parentCall.getParentNode().orElse(null);
                    if (grandparent instanceof ExpressionStmt) {
                        statementsToRemove.add((ExpressionStmt) grandparent);
                    }
                }
            }
        }
    }
}

